const buildDirectorPersonaPrompt = (personas: DirectorPersona[], id?: string, customPrompt?: string) => {
    const persona = personas.find((item) => item.id === id);
    if (!persona || persona.id === 'none') return '';
    if (persona.id === 'custom') return (customPrompt || '').trim();
    return persona.prompt;
};

const normalizePersonaId = (value?: string) =>
    value?.trim().toLowerCase().replace(/\s+/g, '_').replace(/-+/g, '_') || '';

const normalizeCustomPersonas = (value: any): DirectorPersona[] => {
    const rawList = Array.isArray(value) ? value : value ? [value] : [];
    const result: DirectorPersona[] = [];
    rawList.forEach((item) => {
        if (!item || typeof item !== 'object') return;
        const label = String(item.label || item.name || '').trim();
        const prompt = String(item.prompt || '').trim();
        if (!label || !prompt) return;
        const id = normalizePersonaId(item.id || label);
        if (!id || id === 'none' || id === 'custom') return;
        result.push({
            id,
            label,
            summary: String(item.summary || 'Custom persona').trim(),
            prompt,
        });
    });
    return result;
};

const DIRECTOR_SCENE_HEADER_REGEX = /^\s*(?:\[SCENE\]\s*)?(?:SCENE\s*[:\-]\s*)?(?:\d{1,4}[A-Z]?(?:[.)-])?\s+)?(?:INT\.?|EXT\.?|INT\/EXT\.?|EXT\/INT\.?|I\/E\.?|E\/I\.?)/i;

const splitScriptIntoSceneBlocks = (scriptText: string): ScriptSceneBlock[] => {
    if (!scriptText || !scriptText.trim()) return [];
    const lines = scriptText.replace(/\r/g, '\n').split('\n');
    const blocks: ScriptSceneBlock[] = [];
    let currentLines: string[] = [];
    let currentSlugline = '';
    let sceneIndex = 0;

    const flush = () => {
        if (currentLines.length === 0) return;
        const text = currentLines.join('\n').trim();
        if (!text) {
            currentLines = [];
            currentSlugline = '';
            return;
        }
        sceneIndex += 1;
        blocks.push({
            sceneNumber: sceneIndex,
            slugline: currentSlugline || `SCENE ${sceneIndex}`,
            text,
        });
        currentLines = [];
        currentSlugline = '';
    };

    lines.forEach((line) => {
        const trimmed = line.trim();
        if (DIRECTOR_SCENE_HEADER_REGEX.test(trimmed)) {
            flush();
            currentSlugline = trimmed.replace(/\s+/g, ' ').toUpperCase();
            currentLines = [line];
            return;
        }
        if (currentLines.length > 0) {
            currentLines.push(line);
        }
    });
    flush();

    if (blocks.length > 0) return blocks;
    return [{ sceneNumber: 1, slugline: 'SCENE 1', text: scriptText.trim() }];
};

const parseSceneListInput = (input: string, maxSceneNumber: number) => {
    const tokens = input
        .split(/[\s,;]+/)
        .map((token) => token.trim())
        .filter(Boolean);
    const sceneNumbers: number[] = [];
    const invalidTokens: string[] = [];
    const outOfRange: number[] = [];

    tokens.forEach((token) => {
        const rangeMatch = token.match(/^(\d+)-(\d+)$/);
        if (rangeMatch) {
            const rawStart = Number.parseInt(rangeMatch[1], 10);
            const rawEnd = Number.parseInt(rangeMatch[2], 10);
            const start = Math.min(rawStart, rawEnd);
            const end = Math.max(rawStart, rawEnd);
            if (!Number.isFinite(start) || !Number.isFinite(end) || start <= 0 || end <= 0) {
                invalidTokens.push(token);
                return;
            }
            for (let value = start; value <= end; value += 1) {
                if (value > maxSceneNumber) {
                    outOfRange.push(value);
                } else {
                    sceneNumbers.push(value);
                }
            }
            return;
        }

        if (/^\d+$/.test(token)) {
            const value = Number.parseInt(token, 10);
            if (!Number.isFinite(value) || value <= 0) {
                invalidTokens.push(token);
            } else if (value > maxSceneNumber) {
                outOfRange.push(value);
            } else {
                sceneNumbers.push(value);
            }
            return;
        }

        invalidTokens.push(token);
    });

    return {
        sceneNumbers: Array.from(new Set(sceneNumbers)).sort((a, b) => a - b),
        invalidTokens,
        outOfRange: Array.from(new Set(outOfRange)).sort((a, b) => a - b),
    };
};

const formatSceneNumberRanges = (sceneNumbers: number[]) => {
    if (sceneNumbers.length === 0) return '';
    const sorted = Array.from(new Set(sceneNumbers)).sort((a, b) => a - b);
    const parts: string[] = [];
    let start = sorted[0];
    let end = sorted[0];

    for (let i = 1; i < sorted.length; i += 1) {
        const value = sorted[i];
        if (value === end + 1) {
            end = value;
            continue;
        }
        parts.push(start === end ? `${start}` : `${start}-${end}`);
        start = value;
        end = value;
    }
    parts.push(start === end ? `${start}` : `${start}-${end}`);

    return parts.join(', ');
};

const CINEMASCOPE_RATIOS: Record<string, number> = {
    '2.39:1': 2.39,
    '239:100': 2.39,
    '235:100': 2.35,
};
const PHOTOREALISM_HINT = 'realistic lighting, natural textures, real-world detail, lifelike skin tones, no illustration, no CGI';
const DEFAULT_RELIGHT_SETTINGS: RelightSettings = {
    presetId: RELIGHT_PRESETS[0]?.id || 'neutral',
    directionId: RELIGHT_DIRECTIONS[0]?.id || 'front',
    intensity: 0.7,
    softness: 0.6,
    color: '#ffffff',
    environment: '',
    notes: '',
};

const isPhotorealisticStyle = (style: string) => /photo\s*real|photoreal/i.test(style);
const isCinemascopeRatio = (ratio: AspectRatioOption) => ratio in CINEMASCOPE_RATIOS;
const getCinemascopeRatio = (ratio: AspectRatioOption) => CINEMASCOPE_RATIOS[ratio];
const formatCinemascopeLabel = (ratio: AspectRatioOption) => {
    if (ratio === '235:100') return '2.35:1';
    if (ratio === '239:100') return '2.39:1';
    return ratio;
};
const buildCinemascopeHint = (ratio: AspectRatioOption, override?: string) => {
    if (override) return override;
    return `cinemascope ${formatCinemascopeLabel(ratio)}, anamorphic de-squeezed, widescreen framing`;
};
const buildVerticalCompositionHint = () =>
    'native 9:16 vertical composition, subject centered on the X-axis, eyeline near the upper third, minimal headroom, horizon near the lower third, vertical depth layers from bottom to top, favor 40mm-70mm lensing, avoid ultra-wide distortion and rapid horizontal pans, prioritize full-body singles or vertically isolated details, keep critical action inside the centered safe zone for 4:5 previews and mobile UI overlays';
const buildAspectRatioPromptHint = (ratio: AspectRatioOption, override?: string) => {
    if (ratio === '9:16') {
        return buildVerticalCompositionHint();
    }
    if (isCinemascopeRatio(ratio)) {
        return `${buildCinemascopeHint(ratio, override)}, compose for width, lateral blocking, asymmetrical negative space, layered left-to-right depth, panoramic horizon, and deliberate side-to-side motion`;
    }
    return '';
};
const buildStylePrompt = (style: string) => {
    const clean = style.trim();
    if (!clean) return '';
    if (isPhotorealisticStyle(clean)) {
        return `${clean}, ${PHOTOREALISM_HINT}`;
    }
    return clean;
};
const normalizePresetId = (value?: string) =>
    value?.trim().toLowerCase().replace(/\s+/g, '_').replace(/-+/g, '_') || '';
const SHOT_TYPE_ALIASES: Record<string, string> = {
    portrait: 'closeup',
    close_up: 'closeup',
    closeup_shot: 'closeup',
    close_up_shot: 'closeup',
    extreme_close_up: 'extreme_closeup',
    extreme_closeup_shot: 'extreme_closeup',
    extreme_close_up_shot: 'extreme_closeup',
    medium_shot: 'medium',
    wide_shot: 'wide',
    extreme_wide_shot: 'extreme_wide',
    full_body_shot: 'full_body',
    over_the_shoulder: 'ots',
    over_the_shoulder_shot: 'ots',
    broll: 'b_roll',
};
const LIGHTING_ALIASES: Record<string, string> = {
    golden_hour: 'golden',
    low_key: 'dramatic',
    low_key_shadows: 'dramatic',
    neon_cyberpunk: 'neon',
};
const resolveShotTypePresetId = (value?: string) => {
    const normalized = normalizePresetId(value);
    if (!normalized) return undefined;
    const aliased = SHOT_TYPE_ALIASES[normalized] || normalized;
    return SHOT_TYPE_PRESETS.some((preset) => preset.id === aliased) ? aliased : undefined;
};
const resolveLightingPresetId = (value?: string) => {
    const normalized = normalizePresetId(value);
    if (!normalized) return undefined;
    const aliased = LIGHTING_ALIASES[normalized] || normalized;
    return LIGHTING_PRESETS.some((preset) => preset.id === aliased) ? aliased : undefined;
};
