const PROJECT_HUB_UI_PREFS_KEY = 'project_hub_ui_prefs_v1';
const DIRECTOR_SNAPSHOT_LIMIT = 60;
const STORYBOARD_CONTINUITY_AUTO_REFINE_MAX_ATTEMPTS = 3;
const FILMING_CONTINUITY_AUTO_REFINE_MAX_ATTEMPTS = 3;

type ProjectHubUiPrefs = {
    activePhase?: ProductionPhase;
    conceptEntityTab?: ConceptEntityTab;
    conceptCharacterSubtab?: ConceptCharacterSubtab;
    conceptEnvironmentSubtab?: ConceptEnvironmentSubtab;
    conceptPropSubtab?: ConceptPropSubtab;
    conceptBrandingSubtab?: ConceptBrandingSubtab;
    referenceImageModel?: ReferenceImageModel;
    marketingImageModel?: MarketingImageModel;
    videoModel?: FilmingVideoModel;
    directorSceneTargetMode?: DirectorSceneTargetMode;
    directorSceneRangeStart?: string;
    directorSceneRangeEnd?: string;
    directorSceneListInput?: string;
    useGeminiContextMemory?: boolean;
    useStoryboardContinuityAutoRefine?: boolean;
    useFilmingContinuityAutoRefine?: boolean;
};

const isProductionPhase = (value: string): value is ProductionPhase =>
    ALL_PHASES.some((phase) => phase.id === value);

const isConceptEntityTab = (value: string): value is ConceptEntityTab =>
    value === 'characters' || value === 'environments' || value === 'props' || value === 'branding';

const isConceptCharacterSubtab = (value: string): value is ConceptCharacterSubtab =>
    value === 'base_ref' || value === 'angles' || value === 'outfits';

const isConceptEnvironmentSubtab = (value: string): value is ConceptEnvironmentSubtab =>
    value === 'base_ref' || value === 'angles' || value === 'time_of_day';

const isConceptPropSubtab = (value: string): value is ConceptPropSubtab =>
    value === 'base_ref' || value === 'angles' || value === 'state';

const isConceptBrandingSubtab = (value: string): value is ConceptBrandingSubtab =>
    value === 'base_ref' || value === 'variations';

const isReferenceImageModel = (value: string): value is ReferenceImageModel =>
    Object.prototype.hasOwnProperty.call(REFERENCE_MODEL_LABELS, value);

const isMarketingImageModel = (value: string): value is MarketingImageModel =>
    Object.prototype.hasOwnProperty.call(MARKETING_MODEL_LABELS, value);

const isFilmingVideoModel = (value: string): value is FilmingVideoModel =>
    FILMING_VIDEO_MODELS.includes(value as FilmingVideoModel);

const isDirectorSceneTargetMode = (value: string): value is DirectorSceneTargetMode =>
    value === 'all' || value === 'range' || value === 'list';

const readProjectHubUiPrefs = (scope: string): ProjectHubUiPrefs => {
    if (typeof window === 'undefined') return {};
    try {
        const raw = localStorage.getItem(PROJECT_HUB_UI_PREFS_KEY);
        if (!raw) return {};
        const all = JSON.parse(raw) as Record<string, ProjectHubUiPrefs>;
        const scoped = all?.[scope];
        if (!scoped || typeof scoped !== 'object') return {};
        const safe: ProjectHubUiPrefs = {};
        if (typeof scoped.activePhase === 'string' && isProductionPhase(scoped.activePhase)) {
            safe.activePhase = scoped.activePhase;
        }
        if (typeof scoped.conceptEntityTab === 'string' && isConceptEntityTab(scoped.conceptEntityTab)) {
            safe.conceptEntityTab = scoped.conceptEntityTab;
        }
        if (typeof scoped.conceptCharacterSubtab === 'string' && isConceptCharacterSubtab(scoped.conceptCharacterSubtab)) {
            safe.conceptCharacterSubtab = scoped.conceptCharacterSubtab;
        }
        if (typeof scoped.conceptEnvironmentSubtab === 'string' && isConceptEnvironmentSubtab(scoped.conceptEnvironmentSubtab)) {
            safe.conceptEnvironmentSubtab = scoped.conceptEnvironmentSubtab;
        }
        if (typeof scoped.conceptPropSubtab === 'string' && isConceptPropSubtab(scoped.conceptPropSubtab)) {
            safe.conceptPropSubtab = scoped.conceptPropSubtab;
        }
        if (typeof scoped.conceptBrandingSubtab === 'string' && isConceptBrandingSubtab(scoped.conceptBrandingSubtab)) {
            safe.conceptBrandingSubtab = scoped.conceptBrandingSubtab;
        }
        if (typeof scoped.referenceImageModel === 'string' && isReferenceImageModel(scoped.referenceImageModel)) {
            safe.referenceImageModel = scoped.referenceImageModel;
        }
        if (typeof scoped.marketingImageModel === 'string' && isMarketingImageModel(scoped.marketingImageModel)) {
            safe.marketingImageModel = scoped.marketingImageModel;
        }
        if (typeof scoped.videoModel === 'string' && isFilmingVideoModel(scoped.videoModel)) {
            safe.videoModel = scoped.videoModel;
        }
        if (typeof scoped.directorSceneTargetMode === 'string' && isDirectorSceneTargetMode(scoped.directorSceneTargetMode)) {
            safe.directorSceneTargetMode = scoped.directorSceneTargetMode;
        }
        if (typeof scoped.directorSceneRangeStart === 'string') {
            safe.directorSceneRangeStart = scoped.directorSceneRangeStart;
        }
        if (typeof scoped.directorSceneRangeEnd === 'string') {
            safe.directorSceneRangeEnd = scoped.directorSceneRangeEnd;
        }
        if (typeof scoped.directorSceneListInput === 'string') {
            safe.directorSceneListInput = scoped.directorSceneListInput;
        }
        if (typeof scoped.useGeminiContextMemory === 'boolean') {
            safe.useGeminiContextMemory = scoped.useGeminiContextMemory;
        }
        if (typeof scoped.useStoryboardContinuityAutoRefine === 'boolean') {
            safe.useStoryboardContinuityAutoRefine = scoped.useStoryboardContinuityAutoRefine;
        }
        if (typeof scoped.useFilmingContinuityAutoRefine === 'boolean') {
            safe.useFilmingContinuityAutoRefine = scoped.useFilmingContinuityAutoRefine;
        }
        return safe;
    } catch {
        return {};
    }
};

const writeProjectHubUiPrefs = (scope: string, patch: ProjectHubUiPrefs) => {
    if (typeof window === 'undefined') return;
    try {
        const raw = localStorage.getItem(PROJECT_HUB_UI_PREFS_KEY);
        const all = raw ? JSON.parse(raw) as Record<string, ProjectHubUiPrefs> : {};
        all[scope] = { ...(all[scope] || {}), ...patch };
        localStorage.setItem(PROJECT_HUB_UI_PREFS_KEY, JSON.stringify(all));
    } catch {
        // ignore storage errors
    }
};

const formatTimestamp = (value?: string) => {
    if (!value) return '-';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return value;
    return date.toLocaleString();
};

const normalizePath = (value: string) => value.replace(/\\/g, '/').replace(/\/+$/, '').toLowerCase();
const isPathWithinRoot = (root?: string, target?: string | null) => {
    if (!root || !target) return false;
    const normalizedRoot = normalizePath(root);
    const normalizedTarget = normalizePath(target);
    return normalizedTarget === normalizedRoot || normalizedTarget.startsWith(`${normalizedRoot}/`);
};

const resolveModelAspectRatio = (ratio: AspectRatioOption): ModelAspectRatio => (
    isCinemascopeRatio(ratio) ? '16:9' : (ratio as ModelAspectRatio)
);

const cropImageToAspectRatio = async (url: string, targetRatio: number): Promise<string> => {
    try {
        const response = await fetch(url);
        const blob = await response.blob();
        const bitmap = await createImageBitmap(blob);
        const srcWidth = bitmap.width;
        const srcHeight = bitmap.height;
        const srcRatio = srcWidth / srcHeight;

        if (Math.abs(srcRatio - targetRatio) < 0.01) {
            bitmap.close();
            return url;
        }

        let cropWidth = srcWidth;
        let cropHeight = srcHeight;
        let sx = 0;
        let sy = 0;

        if (srcRatio > targetRatio) {
            cropWidth = Math.round(srcHeight * targetRatio);
            sx = Math.round((srcWidth - cropWidth) / 2);
        } else {
            cropHeight = Math.round(srcWidth / targetRatio);
            sy = Math.round((srcHeight - cropHeight) / 2);
        }

        const canvas = document.createElement('canvas');
        canvas.width = cropWidth;
        canvas.height = cropHeight;
        const ctx = canvas.getContext('2d');
        if (!ctx) {
            bitmap.close();
            return url;
        }
        ctx.drawImage(bitmap, sx, sy, cropWidth, cropHeight, 0, 0, cropWidth, cropHeight);
        bitmap.close();

        const croppedBlob = await new Promise<Blob>((resolve) => {
            canvas.toBlob((result) => resolve(result || blob), blob.type || 'image/jpeg', 0.95);
        });
        return URL.createObjectURL(croppedBlob);
    } catch (error) {
        console.warn('Aspect ratio crop failed, using original image.', error);
        return url;
    }
};

const applyCinemascopeCrop = async (media: MediaItem, aspectRatio: AspectRatioOption): Promise<MediaItem> => {
    const targetRatio = getCinemascopeRatio(aspectRatio);
    if (!targetRatio) return media;
    const croppedUrl = await cropImageToAspectRatio(media.url, targetRatio);
    return { ...media, url: croppedUrl };
};

