const buildAngleMetaFromUrls = (urls: string[]): AngleMetadata[] =>
    urls.filter(Boolean).map((url, index) => ({
        id: `angle-${index}`,
        url,
        label: `Angle ${index + 1}`,
    }));

const buildAngleMetaFromPresets = (angles: AnglePreset[], urls: string[]): AngleMetadata[] =>
    angles.flatMap((angle, index) => {
        const url = urls[index];
        if (!url) return [];
        return [{
            id: angle.id,
            angleId: angle.id,
            label: angle.label,
            yaw: angle.yaw,
            pitch: angle.pitch,
            url,
        }];
    });

const getReferenceAngleMeta = (reference: ReferenceItem): AngleMetadata[] => {
    if (reference.multiAngleMeta && reference.multiAngleMeta.length > 0) {
        return reference.multiAngleMeta.filter((meta) => Boolean(meta.url));
    }
    const urls = (reference.multiAngleUrls || []).filter(Boolean);
    if (urls.length === 0) return [];
    return buildAngleMetaFromUrls(urls);
};
